const ALL_TAGS = [...new Set(BLOG_DATA.flatMap(post => post.tags))].sort();

// Export for use in other scripts
if (typeof module !== 'undefined' && module.exports) {
  module.exports = { BLOG_DATA, CATEGORIES, ALL_TAGS };
}
